# scripts/check_promotion_gate.py
import json
import sys
import yaml
import argparse

def load_results(path: str) -> dict:
    with open(path) as f:
        return json.load(f)

def load_manifest(path: str) -> dict:
    with open(path) as f:
        return yaml.safe_load(f)

def check_gate(results: dict, manifest: dict) -> list[str]:
    failures = []
    rules = manifest["promotion_rules"]

    pass_rate = results["summary"]["pass_rate"]
    regressions = results["summary"].get("regression_count", 0)
    coverage = results["summary"].get("coverage_ratio", 1.0)

    if pass_rate < rules["min_pass_rate"]:
        failures.append(
            f"pass_rate {pass_rate:.3f} < threshold {rules['min_pass_rate']}"
        )

    if regressions > rules["max_regression_count"]:
        failures.append(
            f"{regressions} regressions found (max allowed: {rules['max_regression_count']})"
        )

    if coverage < rules["min_coverage_ratio"]:
        failures.append(
            f"coverage {coverage:.3f} < threshold {rules['min_coverage_ratio']}"
        )

    return failures

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--results", required=True)
    parser.add_argument("--manifest", required=True)
    args = parser.parse_args()

    results = load_results(args.results)
    manifest = load_manifest(args.manifest)
    failures = check_gate(results, manifest)

    if failures:
        print("PROMOTION GATE FAILED:")
        for f in failures:
            print(f"  - {f}")
        sys.exit(1)
    else:
        print(f"PROMOTION GATE PASSED: pass_rate={results['summary']['pass_rate']:.3f}")

if __name__ == "__main__":
    main()
